import {
  CanActivate,
  ExecutionContext,
  Injectable,
  UnauthorizedException,
} from '@nestjs/common';
import { Reflector } from '@nestjs/core';
import { JwtService } from '@nestjs/jwt';
import { TransactionHost } from '@nestjs-cls/transactional';

import {
  AdminEntity,
  AuthenticatorEntity,
  Permission,
  UserEntity,
  UserRole,
  UserStatus,
} from '@/db';

import { ContextService, TransactionalAdapterTypeOrm } from '@/modules/global';
import { UN_PROTECT_KEY } from '../decorators';
import { CognitoService } from '../services';
import { AuthenticatedPersonFastifyRequest } from '../types';
import { EMAIL_AUTH_ENABLED, env } from '@/env';

function extractBearerToken(header: string | undefined) {
  const [type, token] = header ? header.split(' ') : [];

  return type === 'Bearer' ? token : null;
}

@Injectable()
export class AuthGuard implements CanActivate {
  constructor(
    private readonly reflector: Reflector,
    private readonly txHost: TransactionHost<TransactionalAdapterTypeOrm>,
    private readonly cognitoService: CognitoService,
    private readonly contextService: ContextService,
    private readonly jwtService: JwtService,
  ) {}

  public async canActivate(context: ExecutionContext): Promise<boolean> {
    const isUnProtectedDecoratorSpecified =
      this.reflector.getAllAndOverride<boolean>(UN_PROTECT_KEY, [
        context.getHandler(),
        context.getClass(),
      ]);

    if (isUnProtectedDecoratorSpecified) {
      return true;
    }

    const type = context.getType();

    const requiredUserRoles = this.reflector.getAllAndOverride<UserRole[]>(
      'roles',
      [context.getHandler(), context.getClass()],
    );

    const requiredPermission = this.reflector.getAllAndOverride<Permission>(
      'permission',
      [context.getHandler(), context.getClass()],
    );

    if (type === 'http') {
      return this.handleHttp(context, requiredUserRoles, requiredPermission);
    }

    return false;
  }

  private async handleHttp(
    context: ExecutionContext,
    userRoles: UserRole[],
    permission: Permission,
  ) {
    const request = context
      .switchToHttp()
      .getRequest<AuthenticatedPersonFastifyRequest>();
    const jwt = extractBearerToken(request.headers.authorization);

    if (!jwt) {
      throw new UnauthorizedException();
    }

    let email: string;

    if (EMAIL_AUTH_ENABLED) {
      email = await this.resolveEmailDev(jwt);
    } else {
      email = await this.resolveEmail(jwt);
    }

    const userRepository = this.txHost.tx.getRepository(UserEntity);

    const user = await userRepository.findOne({
      where: {
        email,
        status: UserStatus.Active,
      },
    });

    if (!user) {
      throw new UnauthorizedException();
    }

    this.contextService.context.user = user;
    this.contextService.context.role = user.selectedRole;

    if (userRoles?.length && !userRoles.includes(user.selectedRole)) {
      throw new UnauthorizedException();
    }

    if (user.selectedRole === UserRole.Authenticator) {
      const authenticatorRepository =
        this.txHost.tx.getRepository(AuthenticatorEntity);
      const authenticator = await authenticatorRepository.findOne({
        where: {
          user: { id: user.id },
        },
      });

      if (!authenticator) {
        throw new UnauthorizedException();
      }

      this.contextService.context.authenticatorId = authenticator.id;
    }

    if ([UserRole.Admin, UserRole.SuperAdmin].includes(user.selectedRole)) {
      const adminRepository = this.txHost.tx.getRepository(AdminEntity);
      const admin = await adminRepository.findOne({
        where: {
          user: { id: user.id },
        },
        relations: ['adminRoles'],
      });

      if (!admin) {
        throw new UnauthorizedException();
      }

      if (user.selectedRole === UserRole.Admin) {
        const adminPermissions = admin.adminRoles.flatMap(
          (role) => role.permissions,
        );

        this.contextService.context.permissions = adminPermissions;
      }

      if (user.selectedRole === UserRole.SuperAdmin) {
        this.contextService.context.permissions = Object.values(Permission);
      }

      this.contextService.context.admin = admin;
    }

    if (
      permission &&
      !this.contextService.context.permissions.includes(permission)
    ) {
      throw new UnauthorizedException();
    }

    request.token = jwt;
    request.user = user;

    return true;
  }

  private async resolveEmail(jwt: string): Promise<string> {
    try {
      return await this.cognitoService.getAccessTokenOwnerEmail(jwt);
    } catch {
      throw new UnauthorizedException();
    }
  }

  private async resolveEmailDev(jwt: string): Promise<string> {
    // 1. Our own JWT (social auth in dev)
    try {
      const payload = this.jwtService.verify<{ sub: string }>(jwt, {
        secret: env.JWT_SECRET,
      });
      if (payload?.sub) return payload.sub;
    } catch {
      // not our JWT
    }

    // 2. Cognito token (social auth via Cognito in dev)
    try {
      return await this.cognitoService.getAccessTokenOwnerEmail(jwt);
    } catch {
      // not a Cognito token
    }

    // 3. Raw email (standard dev login)
    return jwt;
  }
}

