async signInWithGoogleNative(idToken: string) {
  const { email, firstName, lastName, picture } =
    await this.socialAuthService.verifyGoogleToken(idToken);

  return this.txHost.withTransaction(async () => {
    const userRepo = this.txHost.tx.getRepository(UserEntity);
    let user = await userRepo.findOne({ where: { email } });

    if (!user) {
      user = await this.userService.create({
        email,
        firstName,
        lastName,
        patronymic: null,
        roles: [UserRole.Seller],
        status: UserStatus.Active,
        phone: '',
      });
    }

    if (!user.photoFileId && picture) {
      const file = await this.socialAuthService.uploadAvatarFromUrl(picture);
      if (file) {
        await userRepo.update(user.id, { photoFileId: file.id });
      }
    }

    const tokens = await this.cognitoService.signInSocialUser({
      email,
      firstName,
      lastName,
    });

    return { status: 'SUCCESS', payload: tokens };
  });
}
